import os

BASE_DIR = os.path.join(os.path.dirname(__file__), "public")


def read_asset(user_path: str) -> str:
    target = os.path.join(BASE_DIR, user_path)
    with open(target, "r", encoding="utf-8") as fh:
        return fh.read()

